import{o as i,c as n,j as t,n as s,e as r,ae as l,p as h}from"./chunks/framework.BSk3HXt1.js";const c={class:"language-toggle-wrapper"},d={class:"language-toggle-bar"},p={class:"bilingual-title"},g={key:0,class:"zh-text"},u={key:1,class:"en-text"},y=JSON.parse('{"title":"黑洞碰撞證實愛因斯坦與霍金的數十年預測 | Black Hole Collision Confirms Predictions by Einstein and Hawking","description":"天文學家以史無前例的細節觀測到兩顆黑洞碰撞，證實了愛因斯坦「黑洞數學極度簡單」與霍金「黑洞表面積絕不減少」的數十年經典預測。","frontmatter":{"title":"黑洞碰撞證實愛因斯坦與霍金的數十年預測 | Black Hole Collision Confirms Predictions by Einstein and Hawking","description":"天文學家以史無前例的細節觀測到兩顆黑洞碰撞，證實了愛因斯坦「黑洞數學極度簡單」與霍金「黑洞表面積絕不減少」的數十年經典預測。"},"headers":[],"relativePath":"news/black-hole-collision-einstein-hawking.md","filePath":"news/black-hole-collision-einstein-hawking.md"}'),b={name:"news/black-hole-collision-einstein-hawking.md"},w=Object.assign(b,{setup(m){const e=h("bilingual");return(v,a)=>(i(),n("div",null,[t("div",c,[t("div",d,[t("button",{class:s(["language-toggle-btn",{active:e.value==="bilingual"}]),onClick:a[0]||(a[0]=o=>e.value="bilingual")},"中英雙語",2),t("button",{class:s(["language-toggle-btn",{active:e.value==="zh"}]),onClick:a[1]||(a[1]=o=>e.value="zh")},"純中文",2),t("button",{class:s(["language-toggle-btn",{active:e.value==="en"}]),onClick:a[2]||(a[2]=o=>e.value="en")},"純英文",2)])]),t("div",{class:s(["bilingual-article","mode-"+e.value])},[t("h1",p,[e.value!=="en"?(i(),n("span",g,"黑洞碰撞證實愛因斯坦與霍金的數十年預測")):r("",!0),e.value!=="zh"?(i(),n("span",u,"Black Hole Collision Confirms Decades-Old Predictions by Einstein and Hawking")):r("",!0)]),a[3]||(a[3]=l('<div style="text-align:center;margin:24px 0 32px 0;"><img src="/ai-news/black-hole-collision-einstein-hawking/hero.webp" alt="Black Hole Collision Artwork" style="border-radius:16px;max-width:100%;box-shadow:0 8px 32px rgba(0,0,0,0.15);border:1px solid rgba(255,255,255,0.08);"></div><div class="bilingual-paragraph"><p class="zh-text">天文學家以史無前例的細節探測到兩顆黑洞之間的碰撞，為這些宇宙奇觀的本質提供了迄今最清晰的視野，並證實了傳奇物理學家阿爾伯特·愛因斯坦與史蒂芬·霍金數十年前做出的預言。</p><p class="en-text">Astronomers have detected a collision between two black holes in unprecedented detail, offering the clearest view yet into the nature of these cosmic oddities and confirming long-held predictions made by legendary physicists Albert Einstein and Stephen Hawking.</p></div><div class="bilingual-paragraph"><p class="zh-text">這次被命名為 GW250114 的事件發生於今年一月，研究人員透過雷射干涉重力波天文台（LIGO）——位於路易斯安那州利文斯頓和華盛頓州漢福德的兩個完全相同的儀器——觀測到了它。這些儀器探測到了重力波，即兩顆黑洞猛烈碰撞時在時空中產生的微弱漣漪。</p><p class="en-text">The event, dubbed GW250114, became known in January when researchers spotted it with the Laser Interferometer Gravitational-Wave Observatory (LIGO) — a set of two identical instruments located in Livingston, Louisiana, and Hanford, Washington. The instruments detected gravitational waves, faint ripples in space-time produced by the two black holes slamming into each other.</p></div><div class="bilingual-paragraph"><p class="zh-text">尋找重力波（愛因斯坦於 1915 年作為其廣義相對論一部分所預言的現象）是地球上識別黑洞碰撞的唯一方法。愛因斯坦曾認為這些波動太過微弱，人類科技永遠無法偵測，但 LIGO 在 2015 年 9 月首次記錄到了重力波，隨後為三位對這台「黑洞望遠鏡」做出關鍵貢獻的科學家贏得了諾貝爾獎。</p><p class="en-text">Searching for gravitational waves, phenomena predicted in 1915 as part of Einstein’s theory of relativity, is the only way to identify black hole collisions from Earth. Einstein believed that the waves would be too weak to ever be picked up by human technology, but in September 2015, LIGO recorded them for the very first time, later netting a Nobel Prize for three scientists who made key contributions to the development of this “black hole telescope.”</p></div><hr><h2 class="bilingual-header"><span class="zh-text">🌌 完美重現：十年前歷史性發現的超級升級版</span><span class="en-text">A Spectacular Twin to the Historic First Detection</span></h2><div class="bilingual-paragraph"><p class="zh-text">紐約市哥倫比亞大學天文學助理教授暨熨斗研究所計算天體物理中心天體物理學家馬克西米利亞諾·伊西（Maximiliano Isi）表示，新探測到的兩顆黑洞質量分別約為太陽質量的 30 到 35 倍，且自轉非常緩慢。伊西領導了 LIGO-Virgo-KAGRA 合作組織針對 GW250114 數據的新研究，該研究於週三發表在《物理評論快報》（Physical Review Letters）期刊上。</p><p class="en-text">The newly detected black holes were each around 30 to 35 times the mass of the sun, and they were spinning very slowly, said Maximiliano Isi, an assistant professor of astronomy at Columbia University and an astrophysicist at the Flatiron Institute’s Center for Computational Astrophysics in New York City. Isi led a new study for the LIGO-Virgo-KAGRA Collaboration on the GW250114 data, which published Wednesday in the journal Physical Review Letters.</p></div><div class="bilingual-paragraph"><p class="zh-text">「這兩顆黑洞距離我們大約 10 億光年，並以近乎完美的圓形軌道相互繞轉，」伊西說。「合併後產生的新黑洞質量約為太陽質量的 63 倍，並且以每秒 100 圈的速度高速旋轉。」</p><p class="en-text">“The black holes were about 1 billion light years away, and they were orbiting around each other in almost a perfect circle,” Isi said. “The resulting black hole was around 63 times the mass of the sun, and it was spinning at 100 revolutions per second.”</p></div><div class="bilingual-paragraph"><p class="zh-text">伊西指出，這些特徵使得這次合併幾乎是十年前那次開創性歷史首次探測的完美翻版。但現在，由於儀器的性能已大幅提升，科學家能以高得多的清晰度觀察這兩顆黑洞如何互相靠近並合併為一個。他補充，這次觀測為科學家提供了看待「空間與時間動力學」的全新視野。</p><p class="en-text">These characteristics make the merger an almost exact replica of that first, groundbreaking detection from 10 years ago, according to Isi. “But now, because the instruments have improved so much since then, we can see these two black holes with much greater clarity, as they approached each other and merged into a single one,” he added. Isi said the observation gives scientists a totally new view into “the dynamics of space and time.”</p></div><div class="bilingual-paragraph"><p class="zh-text">LIGO 天線由全球約 1,600 名研究人員組成的科學社群共同管理。它能偵測到由重力波引起極其微小的空間拉伸，這相當於「比原子核半徑還要小 1,000 倍的距離變化」。自啟用以來，LIGO 的雷射與反射鏡等關鍵元件經歷了多次升級以提高精準度並減少雜訊，使得這次全新觀測的精確度比十年前首次觀測高出三倍以上。</p><p class="en-text">LIGO, managed by a global scientific community of about 1,600 researchers, works by detecting tiny stretches in space caused by the gravitational waves that amount to “a change in distance that is 1,000 times smaller than the radius of the nucleus of an atom,” as Isi puts it. Since it debuted, some of LIGO’s key components — including its lasers and mirrors — have been upgraded to increase accuracy and reduce background noise. This improved performance made its new observation over three times more precise than the inaugural one a decade ago.</p></div><hr><h2 class="bilingual-header"><span class="zh-text">🔍 證實兩大傳奇預言</span><span class="en-text">Confirming Two Legendary Cosmic Theories</span></h2><div class="dish-card"><div class="dish-card-header"><h3 class="dish-card-title">1. 克爾度規與無毛定理：黑洞極致的簡潔性</h3><span class="dish-card-badge">Roy Kerr 1963</span></div><div class="bilingual-paragraph"><p class="zh-text">第一項預測由紐西蘭數學家羅伊·克爾（Roy Kerr）於 1963 年提出。他基於愛因斯坦的廣義相對論指出，黑洞本質上應該是極其簡單的物體，完全可以用單一公式來描述。</p><p class="en-text">The first prediction, devised by New Zealand mathematician Roy Kerr in 1963, builds upon Einstein’s theory of general relativity, and states that black holes should be paradoxically simple objects, described by a single equation.</p></div><div class="bilingual-paragraph"><p class="zh-text">「是的，黑洞非常神秘、複雜，對宇宙演化有著重要意義，」伊西表示，「但在數學上，我們認為它們應該僅用兩個數字就能完整描述：那就是黑洞的『質量』以及它的『旋轉速度』。關於它們的一切資訊都源自於此。」</p><p class="en-text">“Yes, black holes are very mysterious, complex and have important implications to the evolution of the universe,” Isi said, “but mathematically we think they should be fully described by just two numbers. Everything there is to know about them should come from how big the black hole is — or what its mass is — and how fast it’s rotating.”</p></div><div class="bilingual-paragraph"><p class="zh-text">為了測試這一理論，研究小組利用了黑洞碰撞的一個獨特特徵：新生成的黑洞會產生一種「餘振」（ringing）或震動，就像被敲擊的鐘一樣。鐘聲的音調和持續時間能揭示鐘的材質。新觀測到的 GW250114 餘振信號非常清晰，首次清晰分離出了「基頻」與「第一泛音」（overtone）。這兩個頻率音調完全符合愛因斯坦與克爾的預測，證實了新黑洞確實沒有其他「毛髮」（特徵），純粹由質量和自轉描述！</p><p class="en-text">To test this theory, the researchers used a unique feature of black hole collisions: a “ringing” or vibration — like a bell that’s been struck — that the final black hole produces. “If you have a bell and you strike it with a hammer, it will ring,” Isi noted. “With black holes something similar happens — they ring in gravitational waves.” This ringing includes information about the structure of the black hole. Although the phenomenon was faintly observed before, GW250114 returned a signal with much more clarity, showing both a fundamental mode and an overtone, confirming the black hole is indeed described by just two numbers, mass and rotation.</p></div></div><div class="dish-card"><div class="dish-card-header"><h3 class="dish-card-title">2. 霍金黑洞面積定理：只增不減的宇宙邊界</h3><span class="dish-card-badge">Stephen Hawking 1971</span></div><div class="bilingual-paragraph"><p class="zh-text">第二項預測是英國物理學家史蒂芬·霍金（Stephen Hawking）於 1971 年提出的黑洞面積定理：當兩顆黑洞合併時，最終生成的黑洞表面積（事件視界）必須大於或等於原本兩顆黑洞表面積之和。</p><p class="en-text">The second prediction confirmed by GW250114 is one made in 1971 by British physicist Stephen Hawking, which states that when two black holes merge, the resulting surface area must be equal to or greater than that of the original black holes.</p></div><div class="bilingual-paragraph"><p class="zh-text">伊西解釋說：「這是一個深奧但極其簡單的定理，它指出黑洞的總表面積永遠不會減少，只能變大或保持不變。」由於本次信號極為清晰，科學家能準確推導出合併前兩顆獨立黑洞的面積，並與合併後新黑洞的面積進行對比，為該定理提供了迄今為止最無懈可擊的觀測證據。</p><p class="en-text">“It’s a profound, but very simple theorem that says the total surface area of a black hole can never decrease — it can only get bigger or stay the same,” Isi said. Because of the unprecedented clarity of the new signal, researchers could infer the areas of the black holes early on, measure the area of the final black hole, and confirm the theorem with unparalleled confidence.</p></div><div class="bilingual-paragraph"><p class="zh-text">獲得諾貝爾獎的 LIGO 奠基人之一基普·索恩（Kip Thorne）回憶道，霍金在 2015 年得知首次探測到重力波後，第一時間就打電話給他，詢問 LIGO 是否有能力測試他的面積定理。「如果霍金今天還活著，看到合併黑洞面積增加的確確證據，他一定會欣喜若狂，」索恩在聲明中感嘆。霍金於 2018 年逝世。</p><p class="en-text">Kip Thorne, one of the three recipients of the Nobel Prize for LIGO contributions, said Hawking called him as soon as he learned of the 2015 gravitational wave detection to ask if LIGO would be able to test his theorem. “If Hawking were alive, he would have reveled in seeing the area of the merged black holes increase,” Thorne said of the esteemed physicist, who died in 2018, in a statement.</p></div></div><hr><h2 class="bilingual-header"><span class="zh-text">🚀 重力波天文學的全新里程碑</span><span class="en-text">A Brand New Milestone for Physics</span></h2><div class="bilingual-paragraph"><p class="zh-text">約翰霍普金斯大學物理與天文學教授埃馬努埃萊·貝爾蒂（Emanuele Berti，未參與研究）指出，觀測重力波常被形容為「在乾草堆中尋找一根針」，而升級後的 LIGO 就像是一組超級助聽器，讓科學家聽得更清晰，進而測試十年前無法測試的萬有引力基本原理。</p><p class="en-text">Gravitational waves are very weak, and the titanic task of detecting them is often described as looking for a needle in a haystack, according to Emanuele Berti, a professor of physics and astronomy at Johns Hopkins University who was not involved with the study. He described the LIGO detectors as “hearing aids” that help with this process. “We can now hear the signals with much higher clarity and test fundamental principles of gravity that we could not test ten years ago.”</p></div><div class="bilingual-paragraph"><p class="zh-text">英國修咸頓大學數學物理學教授萊奧·巴拉克（Leor Barack）也讚嘆道，在 LIGO 記錄的 300 多起黑洞合併中，這一次「特別壯觀」，首次實現了對黑洞餘振「第一泛音」的清晰擷取，是迄今為止最精確的黑洞餘振測試。</p><p class="en-text">Leor Barack, a professor of mathematical physics at the University of Southampton in England who was also not part of the study, noted that among the more than 300 black-hole merger events recorded by LIGO, the latest one stands out as “particularly spectacular,” and has achieved, for the first time, a clear extraction of the first ‘overtone’, a fainter harmonious sound of the ringing hole. “This kind of test is the most precise to date, by a long margin.”</p></div><div class="bilingual-paragraph"><p class="zh-text">證實霍金的面積定理與克爾方程，不僅讓我們更深刻地理解黑洞，還可能為物理學的終極聖盃——將描述宏觀引力的廣義相對論與描述微觀亞原子的量子力學進行統一整合——提供關鍵的觀測基石與線索。這為探索時空與引力的邊界鋪平了道路。</p><p class="en-text">Confirming Hawking’s equation and Kerr&#39;s theory could have implications for a very sought-after goal in physics — combining the seemingly incompatible theory of general relativity, which describes gravity, with quantum mechanics, which relates to the subatomic world. These future observations promise to provide more precise tests of our understanding of spacetime and gravity.</p></div><div class="original-source-wrapper"><div class="source-label"><span class="zh-text">🌐 閱讀英文原文：</span><span class="en-text">🌐 Read Original Article:</span></div><a href="https://edition.cnn.com/2025/09/11/science/black-hole-collision-einstein-hawking" target="_blank" rel="noopener noreferrer" class="source-link-btn"> CNN Science <span style="font-size:0.8rem;">↗</span></a></div>',20))],2)]))}});export{y as __pageData,w as default};
